root.sql:
SELECT sc_lon_m_loan_request.loan_requestment_no ,sc_lon_m_loan_request.requestment_date ,pka_com_function.fp_get_thaidate(sc_lon_m_loan_request.requestment_date,'dd Month yyyy') th_date ,sc_lon_m_loan_request.loan_type ,sc_lon_m_loan_request.membership_no ,pka_com_function.fp_form(sc_lon_m_loan_request.bank_acc_no , 'XXX-X-XXXXX-X') as bank_acc_no ,(select sc_acc_m_ucf_bank.short_name from sc_lon_m_loan_request_mpaid ,sc_acc_m_ucf_bank where sc_lon_m_loan_request_mpaid.bank_code = sc_acc_m_ucf_bank.bank_id and sc_lon_m_loan_request_mpaid.loan_requestment_no = sc_lon_m_loan_request.loan_requestment_no and sc_lon_m_loan_request_mpaid.type_pay_money = 'TRB' ) as short_name ,pka_com_function.fp_get_member_name(sc_lon_m_loan_request.membership_no) as member_name ,sc_lon_m_loan_request.loan_request_amount ,sc_lon_m_loan_request.mem_request_amount ,sc_lon_m_loan_request.period_payment_amount ,sc_lon_m_loan_request.loan_installment_amount ,sc_lon_m_loan_request.begining_of_contract ,sc_lon_m_loan_request.remark ,sc_lon_m_loan_request.start_keep_date ,sc_mem_m_membership_registered.member_group_no ,sc_mem_m_ucf_member_group.member_group_control ,sc_mem_m_membership_registered.salary_amount ,sc_lon_m_loan_request.total_old_loan ,sc_lon_m_loan_request.buy_share ,sc_lon_m_rule.loan_type_description ,sc_lon_m_loan_request.max_loan_permit ,'' AS request_coll ,sc_lon_m_loan_request.contract_code ,sc_lon_m_loan_request.total_oldint ,sc_lon_m_loan_request.mem_request_amount ,sc_lon_m_loan_request.loan_payment_type_code ,sc_lon_m_loan_request.branch_id ,sc_lon_m_ucf_loan_obj.loan_objective_description ,sc_mem_m_share_mem.share_stock ,sc_mem_m_share_mem.pending_amt ,sc_lon_m_loan_request.entry_id ,sc_lon_m_loan_request.fee_amount ,sc_lon_m_loan_request.welfare_status ,pka_com_function.fp_get_thaidate( '!requestment_date_1!' ) as requestment_date1 ,pka_com_function.fp_get_thaidate( '!requestment_date_2!' ) as requestment_date2 FROM sc_lon_m_loan_request ,sc_mem_m_membership_registered ,sc_mem_m_ucf_member_group ,sc_lon_m_rule ,sc_lon_m_ucf_loan_obj ,sc_mem_m_share_mem WHERE (sc_lon_m_loan_request.membership_no = sc_mem_m_membership_registered.membership_no) AND (sc_mem_m_membership_registered.member_group_no = sc_mem_m_ucf_member_group.member_group_no) AND (sc_lon_m_rule.loan_type = sc_lon_m_loan_request.loan_type) AND (sc_lon_m_rule.loan_type = sc_lon_m_ucf_loan_obj.loan_type) AND (sc_lon_m_ucf_loan_obj.loan_objective_code = sc_lon_m_loan_request.loan_objective_code) AND (sc_mem_m_membership_registered.membership_no = sc_mem_m_share_mem.membership_no) -- AND (sc_lon_m_loan_request.loan_type = :as_loantype) -- AND (sc_lon_m_loan_request.contract_code = :as_contract_code) AND ( sc_lon_m_loan_request.requestment_date BETWEEN '!requestment_date_1!' AND '!requestment_date_2!')
/*WHERE*/
order by sc_lon_m_loan_request.requestment_date , sc_lon_m_loan_request.loan_requestment_no asc
